import React from "react"

import Home from "./pages/Home"
import {Routes, Route} from "react-router-dom"
// import axios from "axios"


class App extends React.Component {
    render() {
        return (<div>
            <Routes>
                <Switch>
                    <Route path='/' element={<Home />}></Route>
                </Switch>
            </Routes>
        </div>)
    }
}



export default App
